// Login
loginPage.login(this.userData.username, this.userData.password);
// Login validations
cy.url().should('include', '/inventory');
cy.contains('Products').should('be.visible');
// Add products
inventoryPage.addBackpackToCart();
inventoryPage.addBikeLightToCart();
// Cart badge validation
inventoryPage.elements.cartBadge().should('contain', '2');
// Open cart
inventoryPage.openCart();
// Product validations
cartPage.elements.backpackItem().should('be.visible');
cartPage.elements.bikeLightItem().should('be.visible');
// Checkout
cartPage.clickCheckout();
// Checkout form validations
checkoutPage.elements.firstNameInput().should('be.visible');
checkoutPage.fillCheckoutInformation(this.userData.firstName, this.userData.lastName, this.userData.postalCode);
checkoutPage.continueCheckout();
// Overview validations
overviewPage.elements.overviewTitle().should('be.visible');
// Finish purchase
overviewPage.finishPurchase();
// Success validation
overviewPage.elements.successMessage().should('be.visible');
